import { useState, useEffect } from "react";
import { Settings, Server, Flame, HardDrive, Cpu, Mail, CheckCircle2, XCircle, Terminal, Trash2, Edit2 } from "lucide-react";

export default function DeletePath({ selectedUser, nodes, nodesWithTokens, rf, consistency, autoPlayId, downNodes = new Set() }) {
  const [step, setStep] = useState(0);
  const [isSuccess, setIsSuccess] = useState(true);

  // Explications pour chaque phase
  const stepDescriptions = [
    { 
      title: "Prêt à écrire", 
      desc: "Le client prépare l'envoi de la donnée. Dans Cassandra, le client peut se connecter à n'importe quel nœud du cluster, qui agira alors comme Coordinateur pour cette requête.",
      module: null
    },
    { 
      title: "Phase 1 : Partitionnement", 
      desc: "Le Client envoie la donnée au Coordinateur. Celui-ci hache la clé primaire (Murmur3) pour obtenir un Token. Grâce à ce Token, il sait exactement quel nœud est le propriétaire principal de cette donnée sur l'anneau.",
      module: "Partitionnement"
    },
    { 
      title: "Phase 2 : Réplication", 
      desc: `Le Coordinateur ne stocke pas forcément la donnée lui-même. Il la transfère en parallèle aux ${rf} nœuds réplicas responsables (selon votre Facteur de Réplication RF=${rf}).`,
      module: "Réplication"
    },
    { 
      title: "Phase 3 : Moteur de Stockage", 
      desc: "Sur CHAQUE réplica, la donnée est écrite simultanément : d'abord de manière séquentielle dans le CommitLog sur disque (pour ne jamais la perdre en cas de crash), puis dans la Memtable en RAM (pour des lectures ultra-rapides).",
      module: "Stockage Interne"
    },
    { 
      title: "Phase 4 : Consistance & Pannes", 
      desc: `Le Coordinateur attend les acquittements (ACKs) des réplicas. Avec une consistance ${consistency}, il n'a pas besoin d'attendre tout le monde ! Si un nœud est en panne ou lent, la requête peut quand même réussir si le Quorum est atteint.`,
      module: "Pannes & Quorum"
    },
    { 
      title: "Phase 5 : Résultat", 
      desc: isSuccess 
        ? "Le niveau de consistance requis a été atteint. Le Coordinateur renvoie l'acquittement global au Client. L'écriture est terminée avec succès ! Plus tard, la Memtable sera flushée en SSTable."
        : "ÉCHEC (UnavailableException). Le nombre de réplicas en ligne n'a pas permis d'atteindre le Quorum requis par la consistance. Le Coordinateur renvoie une erreur au Client.",
      module: "Terminé"
    }
  ];

  useEffect(() => {
    setStep(0);
  }, [selectedUser, rf, consistency, downNodes]);

  useEffect(() => {
    if (autoPlayId > 0) {
      playAnimation();
    }
  }, [autoPlayId]);

  const playAnimation = () => {
    setStep(0);
    setTimeout(() => setStep(1), 500);   // Partitionnement
    setTimeout(() => setStep(2), 5500);  // Réplication (après 5s)
    setTimeout(() => setStep(3), 10500); // Moteur (après 5s)
    setTimeout(() => setStep(4), 15500); // Consistance (après 5s)
    setTimeout(() => setStep(5), 20500); // Succès ou Échec (après 5s)
  };

  // ── Logique NTS avancée ──
  const isNts = consistency.includes("LOCAL") || consistency.includes("EACH") || (typeof rf !== "number");
  // Remarque: Dans App.jsx, pour NTS on passait strategyConfig.
  // Mais ici on n'a pas strategyConfig en prop dans l'ancienne version.
  // On va utiliser une heuristique ou modifier pour bien supporter rfPerDc si dispo.
  
  const getReplicas = () => {
    if (!nodesWithTokens || nodesWithTokens.length === 0 || !selectedUser) return [];

    const t = BigInt(selectedUser.token);

    // Détection NTS via un prop caché ou via le fait que rf est un objet (si rfPerDc est passé)
    // Comme App.jsx passe { rf, strategyConfig... } on doit trouver si c'est NTS.
    // En fait l'ancien composant n'a pas "strategy" ni "rfPerDc". 
    // On va recalculer depuis nodesWithTokens si on voit plusieurs DCs.
    const dcs = [...new Set(nodesWithTokens.map(n => n.datacenter || "dc1"))];
    const isActuallyNts = dcs.length > 1;

    if (!isActuallyNts) {
      const allTokens = [];
      nodesWithTokens.forEach((node, nodeIdx) =>
        (node.tokens || []).forEach(tok => allTokens.push({ token: tok, nodeIdx, address: node.address, datacenter: node.datacenter }))
      );
      allTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
      if (!allTokens.length) return [];

      let primaryIdx = allTokens.findIndex(tok => t <= BigInt(tok.token));
      if (primaryIdx === -1) primaryIdx = 0;

      const replicas = [], seen = new Set();
      let curr = primaryIdx;
      while (replicas.length < rf && replicas.length < nodes.length) {
        const node = allTokens[curr];
        if (!seen.has(node.nodeIdx)) { seen.add(node.nodeIdx); replicas.push(node); }
        curr = (curr + 1) % allTokens.length;
      }
      return replicas;
    }

    // NTS : calcul indépendant par DC
    const replicas = [];
    const byDc = {};
    nodesWithTokens.forEach((node, nodeIdx) => {
      const dc = node.datacenter || "dc1";
      if (!byDc[dc]) byDc[dc] = [];
      byDc[dc].push({ node, nodeIdx });
    });

    // En NTS simulé ici, on suppose RF=3 par DC
    const simulatedRfPerDc = rf || 3;

    Object.entries(byDc).forEach(([dc, dcNodes]) => {
      const dcTokens = [];
      dcNodes.forEach(({ node, nodeIdx }) => {
        (node.tokens || []).forEach(tok => dcTokens.push({ token: tok, nodeIdx, address: node.address, datacenter: node.datacenter }));
      });
      if (!dcTokens.length) return;

      dcTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
      
      let primaryIdx = dcTokens.findIndex(tok => t <= BigInt(tok.token));
      if (primaryIdx === -1) primaryIdx = 0;

      const dcReplicas = [];
      const seen = new Set();
      let curr = primaryIdx;
      
      while (dcReplicas.length < simulatedRfPerDc && dcReplicas.length < dcNodes.length) {
        const node = dcTokens[curr];
        if (!seen.has(node.nodeIdx)) {
          seen.add(node.nodeIdx);
          dcReplicas.push(node);
        }
        curr = (curr + 1) % dcTokens.length;
      }
      replicas.push(...dcReplicas);
    });

    return replicas;
  };

  const replicas = getReplicas();
  const dcs = [...new Set(replicas.map(r => r.datacenter || "dc1"))];
  const isActualNts = dcs.length > 1;

  const getRequiredAcks = () => {
    if (!isActualNts) {
      if (consistency === "ONE") return 1;
      if (consistency === "ALL") return rf;
      return Math.floor(rf / 2) + 1;
    }
    if (consistency === "LOCAL_QUORUM") { return Math.floor(rf / 2) + 1; }
    if (consistency === "LOCAL_ONE") return 1;
    if (consistency === "EACH_QUORUM") { return dcs.length * (Math.floor(rf / 2) + 1); }
    if (consistency === "ALL") return replicas.length;
    if (consistency === "ONE") return 1;
    return Math.floor(rf / 2) + 1;
  };
  const requiredAcks = getRequiredAcks();

  // Calcul du succès en fonction des nœuds en panne
  useEffect(() => {
    let upReplicasCount = 0;
    replicas.forEach(r => {
      const isSimDown = downNodes.has(r.address);
      const isReallyDown = nodes.find(n => n.address === r.address)?.is_up === false;
      if (!isSimDown && !isReallyDown) {
        upReplicasCount++;
      }
    });
    setIsSuccess(upReplicasCount >= requiredAcks);
  }, [replicas, downNodes, requiredAcks, nodes]);

  return (
    <div style={{ display: "grid", gridTemplateColumns: "350px 1fr", gap: "2rem", minHeight: "750px", alignItems: "stretch" }}>
      
      {/* Colonne Gauche : Narratif et Explications */}
      <div className="card" style={{ display: "flex", flexDirection: "column", background: "var(--bg-sidebar)", borderRight: "1px solid var(--border-light)" }}>
        <h2 style={{ margin: "0 0 1rem", color: "var(--text-primary)", fontSize: "1.4rem" }}>L'Anatomie d'une Suppression</h2>
        <p style={{ margin: "0 0 2rem", color: "var(--text-secondary)", fontSize: "14px", lineHeight: 1.6 }}>
          Découvrez comment Cassandra gère la <strong>Suppression (Tombstone)</strong>, la <strong>Réplication</strong> et la <strong>Consistance</strong> pour la donnée <span style={{color: "var(--error-color)", fontWeight: "bold"}}>{selectedUser?.user_id}</span>.
        </p>

        <button className="btn btn-primary" onClick={playAnimation} style={{ padding: "1rem", fontSize: "15px", marginBottom: "2rem", width: "100%", background: "var(--error-color)", borderColor: "var(--error-color)" }}>
          ▶ Lancer l'Animation Complète
        </button>

        {/* Panneau d'explication dynamique */}
        <div style={{ 
          flex: 1, 
          background: step > 0 ? "var(--error-bg)" : "var(--bg-surface)", 
          border: step > 0 ? "1px solid var(--error-color)" : "1px solid var(--border-light)",
          borderRadius: "var(--radius-lg)", 
          padding: "1.5rem",
          transition: "all 0.3s ease",
          boxShadow: step > 0 ? "0 4px 12px rgba(239, 68, 68, 0.15)" : "none"
        }}>
          {stepDescriptions[step].module && (
            <div style={{ fontSize: 11, fontWeight: 700, color: "var(--error-color)", textTransform: "uppercase", letterSpacing: 1, marginBottom: 8 }}>
              Concept : {stepDescriptions[step].module}
            </div>
          )}
          <h3 style={{ margin: "0 0 1rem", color: "#dc2626", fontSize: "1.2rem", display: "flex", alignItems: "center", gap: "0.5rem" }}>
            <span style={{ background: "var(--error-color)", color: "white", width: "24px", height: "24px", display: "inline-flex", alignItems: "center", justifyContent: "center", borderRadius: "50%", fontSize: "12px" }}>
              {step}
            </span>
            {stepDescriptions[step].title}
          </h3>
          <p style={{ margin: 0, color: "var(--text-primary)", lineHeight: 1.6, fontSize: "14px" }}>
            {stepDescriptions[step].desc}
          </p>

          {/* Mini-Stats en fonction de l'étape */}
          {step === 4 && (
             <div style={{ marginTop: "1.5rem", padding: "1rem", background: "white", borderRadius: "var(--radius-md)", border: "1px dashed var(--warning-color)" }}>
               <strong style={{fontSize: "13px", color: "var(--warning-color)"}}>Consistance {consistency}</strong>
               <div style={{fontSize: "12px", color: "var(--text-secondary)", marginTop: "4px"}}>
                 Le Coordinateur a besoin de <strong>{requiredAcks} ACK(s)</strong> sur {rf} pour considérer l'écriture réussie.
               </div>
             </div>
          )}
        </div>
      </div>

      {/* Colonne Droite : Le Cluster Animé */}
      <div className="card" style={{ position: "relative", background: "var(--bg-app)", overflow: "hidden", display: "flex", justifyContent: "center", alignItems: "center" }}>
        
        <div style={{ width: "100%", height: "100%", position: "relative", maxWidth: "800px", maxHeight: "750px", minHeight: "600px" }}>
          
          {/* SVG Lignes de connexion */}
          <svg style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", zIndex: 1, pointerEvents: "none" }}>
            {/* Ligne Client -> Coordinateur */}
            <path d="M 10% 50% L 35% 50%" stroke="var(--border-light)" strokeWidth="3" strokeDasharray="5,5" fill="none" />
            
            {/* Lignes Coordinateur -> Replicas */}
            {replicas.map((r, i) => {
              const startX = "35%";
              const startY = "50%";
              const endX = "75%";
              const endY = `${8 + (i * (84 / (replicas.length === 1 ? 1 : replicas.length - 1)))}%`; // Distribuer verticalement
              return (
                <line key={`line-${i}`} x1={startX} y1={startY} x2={endX} y2={endY} stroke="var(--border-light)" strokeWidth="2" strokeDasharray="4,4" />
              );
            })}
          </svg>

          {/* Noeuds du système */}
          
          {/* 1. Client */}
          <div className="system-node client-node" style={{ top: "50%", left: "10%" }}>
            <div style={{ fontSize: "2rem" }}><Terminal size={32} /></div>
            <div className="node-label">Client</div>
          </div>

          {/* 2. Coordinateur */}
          <div className={`system-node coord-node ${step >= 1 && step < 5 ? 'active-node' : ''}`} style={{ top: "50%", left: "35%" }}>
            <div style={{ fontSize: "2.5rem" }}><Settings size={40} color="var(--text-tertiary)" /></div>
            <div className="node-label">Coordinateur</div>
            {step === 1 && <span className="status-badge ping-badge">Hashing (Murmur3)</span>}
            {step === 4 && <span className="status-badge" style={{background:"var(--warning-color)", color:"white"}}>Attente ACKs...</span>}
          </div>

          {/* 3. Replicas */}
          {replicas.map((r, i) => {
            const topPos = `${8 + (i * (84 / (replicas.length === 1 ? 1 : replicas.length - 1)))}%`;
            const isActive = step >= 2 && step <= 4;
            const isWriting = step === 3;
            
            const isSimDown = downNodes.has(r.address);
            const isReallyDown = nodes.find(n => n.address === r.address)?.is_up === false;
            const isDown = isSimDown || isReallyDown;
            const isDcPrimary = isActualNts && (i === 0 || replicas[i - 1].datacenter !== r.datacenter);

            return (
              <div key={r.nodeIdx} className={`system-node replica-node ${isActive && !isDown ? 'active-node' : ''}`} style={{ 
                top: topPos, left: "75%", width: "160px", transform: "translateY(-50%)",
                borderColor: isDown ? "var(--error-color)" : "var(--border-light)",
                background: isDown ? "var(--error-bg)" : "var(--bg-surface)",
                opacity: isDown ? 0.7 : 1
              }}>
                <div style={{ fontSize: "1.5rem" }}>{isDown ? <Flame size={24} color="var(--error-color)" /> : <Server size={24} color="var(--text-secondary)" />}</div>
                <div className="node-label" style={{ color: isDown ? "var(--error-color)" : "var(--text-primary)" }}>Nœud {r.nodeIdx + 1} <span style={{fontSize: 10, color: "var(--text-tertiary)"}}>{isActualNts ? `(${r.datacenter})` : ""}</span></div>
                <div style={{ fontSize: "10px", color: "var(--text-tertiary)" }}>{isActualNts ? (isDcPrimary ? "(Primaire Local)" : "(Réplica Local)") : (i === 0 ? "(Primaire)" : "(Réplica)")}</div>
                
                {/* Moteur interne (Memtable/CommitLog) visible à l'étape 3 */}
                {!isDown && (
                  <div className={`internal-engine ${step >= 3 ? 'show-engine' : ''}`}>
                    <div className={`engine-part ${isWriting ? 'flash-write' : ''}`} style={{ borderColor: step >=3 ? '#fca5a5' : '', background: step >=3 ? '#fef2f2' : '', color: step >=3 ? '#dc2626' : '' }}><HardDrive size={14} style={{ marginRight: 4 }}/> CommitLog : <Trash2 size={14} style={{ marginRight: 4 }}/> Tombstone</div>
                    <div className={`engine-part ${isWriting ? 'flash-write' : ''}`} style={{ borderColor: step >=3 ? '#fca5a5' : '', background: step >=3 ? '#fef2f2' : '', color: step >=3 ? '#dc2626' : '' }}><Cpu size={14} style={{ marginRight: 4 }}/> Memtable : <Trash2 size={14} style={{ marginRight: 4 }}/> Tombstone</div>
                  </div>
                )}

                {isDown && <span className="status-badge error-badge" style={{bottom: "-15px"}}>PANNE</span>}
              </div>
            );
          })}


          {/* --- ANIMATIONS DES DONNÉES --- */}

          {/* Phase 1: Client -> Coordinateur */}
          <div className={`data-packet ${step === 1 ? 'anim-c-to-coord' : 'hidden'}`} style={{ '--start-x': '10%', '--start-y': '50%', '--end-x': '35%', '--end-y': '50%' }}>
            <Mail size={14} /> <span>{selectedUser?.user_id}</span>
          </div>

          {/* Phase 2: Coordinateur -> Replicas */}
          {replicas.map((r, i) => {
            const endY = `${8 + (i * (84 / (replicas.length === 1 ? 1 : replicas.length - 1)))}%`;
            return (
              <div key={`p2-${i}`} className={`data-packet packet-copy ${step === 2 ? 'anim-coord-to-rep' : 'hidden'}`} style={{ '--start-x': '35%', '--start-y': '50%', '--end-x': '75%', '--end-y': endY }}>
                <Mail size={14} />
              </div>
            );
          })}

          {/* Phase 4: Replicas -> Coordinateur (ACKs) */}
          {replicas.map((r, i) => {
            const startY = `${8 + (i * (84 / (replicas.length === 1 ? 1 : replicas.length - 1)))}%`;
            const isSimDown = downNodes.has(r.address);
            const isReallyDown = nodes.find(n => n.address === r.address)?.is_up === false;
            const isDown = isSimDown || isReallyDown;
            
            // Ne pas envoyer d'ACK si le noeud est en panne
            if (isDown) return null;

            return (
              <div key={`p4-${i}`} className={`data-packet ack-packet ${step === 4 ? 'anim-rep-to-coord' : 'hidden'}`} style={{ '--start-x': '75%', '--start-y': startY, '--end-x': '35%', '--end-y': '50%' }}>
                <CheckCircle2 size={14} style={{ marginRight: 4 }}/> ACK
              </div>
            );
          })}

          {/* Phase 5: Coordinateur -> Client (Final ACK/ERR) */}
          {isSuccess ? (
            <div className={`data-packet ack-packet ${step === 5 ? 'anim-coord-to-c' : 'hidden'}`} style={{ '--start-x': '35%', '--start-y': '50%', '--end-x': '10%', '--end-y': '50%' }}>
              <CheckCircle2 size={14} style={{ marginRight: 4 }}/> SUCCÈS
            </div>
          ) : (
            <div className={`data-packet ${step === 5 ? 'anim-coord-to-c' : 'hidden'}`} style={{ '--start-x': '35%', '--start-y': '50%', '--end-x': '10%', '--end-y': '50%', borderColor: "var(--error-color)", background: "var(--error-bg)", color: "var(--error-color)" }}>
              <XCircle size={14} style={{ marginRight: 4 }}/> ERREUR
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

import { useState } from "react";
import { Building2, PowerOff, CheckCircle2, XCircle, Star, RefreshCw, RotateCcw } from "lucide-react";

const DC_COLORS = {
  dc1: { primary: "#4f46e5", bg: "#4f46e510", border: "#4f46e550", text: "#818cf8", kill: "#4f46e530" },
  dc2: { primary: "#10b981", bg: "#10b98110", border: "#10b98150", text: "#34d399", kill: "#10b98130" },
};
function getDcColor(dc) { return DC_COLORS[dc] || DC_COLORS.dc1; }

/**
 * Calcule primary + réplicas pour UN DC en suivant l'anneau de tokens (logique Cassandra réelle).
 * Retourne { primaryGlobalIdx, replicaGlobalIdxs } — indices dans le tableau `nodes` global.
 */
function computeDcReplicas(dcNodeEntries, dcNodesWithTokens, selectedUser, dcRf) {
  if (!selectedUser || !dcNodeEntries.length) {
    return { primaryGlobalIdx: dcNodeEntries[0]?.i ?? -1, replicaGlobalIdxs: [] };
  }

  const addrToNWT = new Map((dcNodesWithTokens || []).map(n => [n.address, n]));
  const allTokens = [];
  dcNodeEntries.forEach(({ n, i: globalIdx }, localIdx) => {
    const nwt = addrToNWT.get(n.address) || { tokens: [] };
    (nwt.tokens || []).forEach(tok => allTokens.push({ token: tok, localIdx, globalIdx }));
  });

  if (!allTokens.length) {
    return { primaryGlobalIdx: dcNodeEntries[0]?.i ?? -1, replicaGlobalIdxs: [] };
  }

  try {
    allTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
    const ht = BigInt(selectedUser.token);

    // Trouve le premier token >= ht sur l'anneau (primary)
    let primaryPos = allTokens.findIndex(t => ht <= BigInt(t.token));
    if (primaryPos === -1) primaryPos = 0; // wrap-around

    // Parcourt l'anneau en dédupliquant par nœud pour avoir l'ordre réel des nœuds
    const seenLocal = new Set();
    const ringOrder = []; // { localIdx, globalIdx } dans l'ordre de l'anneau à partir du primary
    for (let step = 0; step < allTokens.length && ringOrder.length < dcNodeEntries.length; step++) {
      const entry = allTokens[(primaryPos + step) % allTokens.length];
      if (!seenLocal.has(entry.localIdx)) {
        seenLocal.add(entry.localIdx);
        ringOrder.push(entry);
      }
    }

    const actualRf = Math.min(dcRf, dcNodeEntries.length);
    const primaryGlobalIdx = ringOrder[0]?.globalIdx ?? dcNodeEntries[0]?.i ?? -1;
    const replicaGlobalIdxs = ringOrder.slice(1, actualRf).map(e => e.globalIdx);
    return { primaryGlobalIdx, replicaGlobalIdxs };
  } catch {
    return { primaryGlobalIdx: dcNodeEntries[0]?.i ?? -1, replicaGlobalIdxs: [] };
  }
}

/**
 * Calcule primary + réplicas pour SimpleStrategy (anneau global unique).
 */
function computeSimpleReplicas(nodesWithTokens, selectedUser, rf, nodes) {
  if (!selectedUser || !nodesWithTokens.length) return { primaryNodeIdx: 0, replicaIdxs: [] };

  const allTokens = [];
  nodesWithTokens.forEach((node, idx) =>
    (node.tokens || []).forEach(tok => allTokens.push({ token: tok, nodeIdx: idx }))
  );

  try {
    allTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
    const ht = BigInt(selectedUser.token);

    let primaryPos = allTokens.findIndex(t => ht <= BigInt(t.token));
    if (primaryPos === -1) primaryPos = 0;

    // Ordre des nœuds uniques sur l'anneau à partir du primary
    const seenNode = new Set();
    const ringOrder = [];
    for (let step = 0; step < allTokens.length && ringOrder.length < nodes.length; step++) {
      const entry = allTokens[(primaryPos + step) % allTokens.length];
      if (!seenNode.has(entry.nodeIdx)) {
        seenNode.add(entry.nodeIdx);
        ringOrder.push(entry.nodeIdx);
      }
    }

    const actualRf = Math.min(rf, nodes.length);
    const primaryNodeIdx = ringOrder[0] ?? 0;
    const replicaIdxs = ringOrder.slice(1, actualRf);
    return { primaryNodeIdx, replicaIdxs };
  } catch {
    return { primaryNodeIdx: 0, replicaIdxs: [] };
  }
}

// ── Calcule si une requête peut aboutir ──────────────────────────────────────
function computeCanRespond({ consistency, nodesHoldingData, nodes, downNodes, rfPerDc, byDc, strategy }) {
  const isNts = strategy === "nts";
  if (!isNts) {
    const actualRf = nodesHoldingData.length;
    let up = 0;
    nodesHoldingData.forEach(idx => {
      const n = nodes[idx];
      if (n && !downNodes.has(n.address) && n.is_up) up++;
    });
    const needed = consistency === "ONE" ? 1 : consistency === "ALL" ? actualRf : Math.floor(actualRf / 2) + 1;
    return { canRespond: up >= needed, details: `${up} / ${needed} réplicas disponibles`, upCount: up, needed };
  }

  // NTS : calcul par DC
  const upByDc = {};
  const rfByDcCalc = {};
  Object.entries(byDc).forEach(([dc, dcNodes]) => {
    const dcRf = rfPerDc?.[dc] ?? 1;
    rfByDcCalc[dc] = dcRf;
    upByDc[dc] = dcNodes.filter(({ n }) => !downNodes.has(n.address) && n.is_up).length;
  });

  const dcList = Object.keys(byDc);
  if (consistency === "LOCAL_QUORUM") {
    const localDc = dcList[0];
    const needed = Math.floor(rfByDcCalc[localDc] / 2) + 1;
    const up = upByDc[localDc] ?? 0;
    return { canRespond: up >= needed, details: `${localDc.toUpperCase()} : ${up}/${needed} requis (LOCAL_QUORUM)`, upCount: up, needed };
  }
  if (consistency === "LOCAL_ONE") {
    const localDc = dcList[0];
    const up = upByDc[localDc] ?? 0;
    return { canRespond: up >= 1, details: `${localDc.toUpperCase()} : ${up}/1 requis (LOCAL_ONE)`, upCount: up, needed: 1 };
  }
  if (consistency === "EACH_QUORUM") {
    const results = dcList.map(dc => {
      const needed = Math.floor(rfByDcCalc[dc] / 2) + 1;
      return { dc, up: upByDc[dc] ?? 0, needed, ok: (upByDc[dc] ?? 0) >= needed };
    });
    const allOk = results.every(r => r.ok);
    const details = results.map(r => `${r.dc.toUpperCase()}: ${r.up}/${r.needed}`).join(" | ");
    return { canRespond: allOk, details: `EACH_QUORUM — ${details}`, upCount: 0, needed: 0 };
  }
  const totalUp = Object.values(upByDc).reduce((s, v) => s + v, 0);
  const totalRf = Object.values(rfByDcCalc).reduce((s, v) => s + v, 0);
  const needed = consistency === "ONE" ? 1 : consistency === "ALL" ? totalRf : Math.floor(totalRf / 2) + 1;
  return { canRespond: totalUp >= needed, details: `Global : ${totalUp}/${needed}`, upCount: totalUp, needed };
}

export default function FailureSimulator({ nodes, nodesWithTokens, selectedUser, rf, rfPerDc, strategy, consistency, downNodes, setDownNodes }) {
  const isNts = strategy === "nts";

  // ── Grouper par DC ───────────────────────────────────────────────────────
  const byDc = {};
  nodes.forEach((n, i) => {
    const dc = n.datacenter || "dc1";
    if (!byDc[dc]) byDc[dc] = [];
    byDc[dc].push({ n, i });
  });

  // ── Calcul des réplicas selon la stratégie ───────────────────────────────
  let primaryNodeIdxs = [];
  let replicaIdxs = [];

  if (isNts) {
    // NTS : calcul indépendant par DC sur l'anneau de tokens local
    Object.entries(byDc).forEach(([dc, dcNodeEntries]) => {
      const dcAddresses = new Set(dcNodeEntries.map(({ n }) => n.address));
      const dcNWT = nodesWithTokens.filter(n => dcAddresses.has(n.address));
      const dcRf = rfPerDc?.[dc] ?? 1;
      const { primaryGlobalIdx, replicaGlobalIdxs } = computeDcReplicas(dcNodeEntries, dcNWT, selectedUser, dcRf);
      if (primaryGlobalIdx >= 0) primaryNodeIdxs.push(primaryGlobalIdx);
      replicaGlobalIdxs.forEach(idx => replicaIdxs.push(idx));
    });
    replicaIdxs = [...new Set(replicaIdxs)];
  } else {
    const result = computeSimpleReplicas(nodesWithTokens, selectedUser, rf, nodes);
    if (result.primaryNodeIdx >= 0) primaryNodeIdxs.push(result.primaryNodeIdx);
    replicaIdxs = result.replicaIdxs;
  }

  const nodesHoldingData = [...primaryNodeIdxs, ...replicaIdxs];

  // ── Actions ──────────────────────────────────────────────────────────────
  const toggle = (addr) => {
    const s = new Set(downNodes);
    s.has(addr) ? s.delete(addr) : s.add(addr);
    setDownNodes(s);
  };

  const killDc = (dc) => {
    const s = new Set(downNodes);
    const dcNodes = byDc[dc] || [];
    const allDown = dcNodes.every(({ n }) => s.has(n.address));
    dcNodes.forEach(({ n }) => allDown ? s.delete(n.address) : s.add(n.address));
    setDownNodes(s);
  };

  const { canRespond, details } = computeCanRespond({ consistency, nodesHoldingData, nodes, downNodes, rfPerDc, byDc, strategy });

  // ── Rendu d'un nœud ──────────────────────────────────────────────────────
  const renderNode = ({ n, i }) => {
    const isPrimary = primaryNodeIdxs.includes(i);
    const isReplica = replicaIdxs.includes(i);
    const hasData = isPrimary || isReplica;
    const nodeColor = `var(--node-${i % 5})`;
    const isSimDown = downNodes.has(n.address);
    const isReallyDown = !n.is_up;
    const isDown = isSimDown || isReallyDown;

    return (
      <div key={n.address} onClick={() => !isReallyDown && toggle(n.address)}
        style={{
          width: 130, padding: "1rem 0.75rem", borderRadius: 12, textAlign: "center",
          cursor: isReallyDown ? "not-allowed" : "pointer", userSelect: "none",
          background: isDown ? "var(--error-bg)" : hasData ? "var(--bg-surface)" : "var(--bg-app)",
          border: `2px solid ${isDown ? "var(--error-color)" : hasData ? nodeColor : "var(--border-light)"}`,
          opacity: isDown ? 0.8 : hasData ? 1 : 0.5,
          transform: isDown ? "scale(0.95)" : "scale(1)",
          transition: "all 0.2s cubic-bezier(0.4,0,0.2,1)",
          position: "relative", overflow: "hidden"
        }}>
        {hasData && !isDown && <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 3, background: nodeColor }} />}
        <div style={{ fontWeight: 700, fontSize: 15, color: isDown ? "var(--error-color)" : "var(--text-primary)" }}>N{i + 1}</div>
        <div style={{ fontSize: 10, color: "var(--text-tertiary)", fontFamily: "monospace", marginTop: 2 }}>{n.address}</div>
        <div style={{ marginTop: "0.6rem" }}>
          {isReallyDown
            ? <span className="badge badge-error" style={{ fontSize: 10 }}><PowerOff size={10} style={{ marginRight: 4 }}/> PANNE RÉELLE</span>
            : isSimDown
              ? <span className="badge badge-error" style={{ fontSize: 10 }}><PowerOff size={10} style={{ marginRight: 4 }}/> SIMULÉE</span>
              : hasData
                ? <span className="badge" style={{ fontSize: 10, background: `${nodeColor}15`, color: nodeColor, border: `1px solid ${nodeColor}40`, display: "flex", alignItems: "center", gap: "0.2rem" }}>
                    {isPrimary ? <><Star size={10} /> PRIMARY</> : <><RefreshCw size={10} /> REPLICA</>}
                  </span>
                : <span className="badge badge-neutral" style={{ fontSize: 10 }}>Vide</span>}
        </div>
        {!isReallyDown && (
          <div style={{ marginTop: 6, fontSize: 10, color: isDown ? "var(--error-color)" : "var(--text-tertiary)", textDecoration: "underline", opacity: 0.7 }}>
            {isDown ? "Remettre en ligne" : "Simuler panne"}
          </div>
        )}
      </div>
    );
  };

  return (
    <div>
      <div className="card" style={{ marginBottom: "2rem" }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1.5rem" }}>
          <div>
            <h2 style={{ margin: "0 0 0.5rem", fontSize: "1.5rem" }}>Simulation de Pannes</h2>
            <p style={{ margin: 0, color: "var(--text-secondary)", fontSize: 14, lineHeight: 1.6, maxWidth: 700 }}>
              {isNts
                ? "Clique sur un nœud ou utilise les boutons « Kill DC » pour simuler une panne de datacenter entier. Observer l'impact selon le niveau de consistance."
                : `Clique sur un nœud pour simuler une panne. Observe si la consistance ${consistency} peut être maintenue.`}
            </p>
          </div>
          <button onClick={() => setDownNodes(new Set())} className="btn btn-outline"><RotateCcw size={14} /> Réinitialiser</button>
        </div>

        {/* Dashboard RF / Consistency */}
        <div style={{ display: "flex", gap: "1rem", flexWrap: "wrap", marginBottom: "2rem", background: "var(--bg-app)", padding: "0.875rem", borderRadius: "var(--radius-md)", border: "1px solid var(--border-light)" }}>
          {isNts && Object.entries(rfPerDc || {}).map(([dc, r]) => (
            <div key={dc} style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              <span style={{ fontSize: 10, color: "var(--text-tertiary)", fontWeight: 600, textTransform: "uppercase" }}>RF {dc.toUpperCase()}</span>
              <span className="badge badge-neutral" style={{ fontSize: 13 }}>{r}</span>
            </div>
          ))}
          {!isNts && (
            <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              <span style={{ fontSize: 10, color: "var(--text-tertiary)", fontWeight: 600, textTransform: "uppercase" }}>RF</span>
              <span className="badge badge-neutral" style={{ fontSize: 13 }}>{Math.min(rf, nodes.length)}</span>
            </div>
          )}
          <div style={{ width: 1, background: "var(--border-light)" }} />
          <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <span style={{ fontSize: 10, color: "var(--text-tertiary)", fontWeight: 600, textTransform: "uppercase" }}>Consistance</span>
            <span className="badge badge-neutral" style={{ fontSize: 13 }}>{consistency}</span>
          </div>
          <div style={{ width: 1, background: "var(--border-light)" }} />
          <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <span style={{ fontSize: 10, color: "var(--text-tertiary)", fontWeight: 600, textTransform: "uppercase" }}>Statut</span>
            <span className={`badge ${canRespond ? "badge-success" : "badge-error"}`} style={{ fontSize: 13 }}>{details}</span>
          </div>
        </div>

        {/* ── Nœuds groupés par DC (NTS) ou à plat (Simple) ── */}
        {isNts ? (
          <div style={{ display: "flex", gap: "1.5rem", flexWrap: "wrap", justifyContent: "center", marginBottom: "2rem" }}>
            {Object.entries(byDc).map(([dc, dcNodes]) => {
              const colors = getDcColor(dc);
              const allDcDown = dcNodes.every(({ n }) => downNodes.has(n.address) || !n.is_up);
              return (
                <div key={dc} style={{ flex: 1, minWidth: 280, background: colors.bg, border: `1.5px solid ${colors.border}`, borderRadius: 16, padding: "1.25rem" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1rem" }}>
                    <span style={{ fontWeight: 700, fontSize: 15, color: colors.primary, display: "flex", alignItems: "center", gap: "0.4rem" }}><Building2 size={16} /> {dc.toUpperCase()}</span>
                    <button onClick={() => killDc(dc)} style={{ fontSize: 11, padding: "4px 10px", borderRadius: 8, cursor: "pointer", border: `1px solid ${colors.border}`, background: allDcDown ? colors.kill : "transparent", color: allDcDown ? colors.primary : colors.text, fontWeight: 600, transition: "all 0.2s", display: "flex", alignItems: "center", gap: "0.3rem" }}>
                      {allDcDown ? <><CheckCircle2 size={12} /> Remettre DC</> : <><PowerOff size={12} /> Kill DC</>}
                    </button>
                  </div>
                  <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap", justifyContent: "center" }}>
                    {dcNodes.map(renderNode)}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{ display: "flex", gap: "1.25rem", flexWrap: "wrap", justifyContent: "center", marginBottom: "2rem" }}>
            {nodes.map((n, i) => renderNode({ n, i }))}
          </div>
        )}

        {/* Résultat final */}
        <div style={{ borderRadius: "var(--radius-lg)", padding: "1.25rem", background: canRespond ? "var(--success-bg)" : "var(--error-bg)", border: `1px solid ${canRespond ? "#6ee7b7" : "#fca5a5"}`, display: "flex", gap: "1rem", alignItems: "flex-start" }}>
          <div style={{ fontSize: "1.5rem", color: canRespond ? "var(--success-color)" : "var(--error-color)", marginTop: "2px" }}>
            {canRespond ? <CheckCircle2 size={24} /> : <XCircle size={24} />}
          </div>
          <div>
            <h3 style={{ margin: "0 0 0.5rem", color: canRespond ? "var(--success-color)" : "var(--error-color)", fontSize: "1.1rem" }}>
              {canRespond ? "SUCCÈS — La requête passera" : "ÉCHEC — UnavailableException"}
            </h3>
            <p style={{ margin: 0, fontSize: 14, lineHeight: 1.5, color: canRespond ? "#065f46" : "#991b1b" }}>
              {canRespond
                ? `Assez de nœuds disponibles pour satisfaire la consistance ${consistency}. (${details})`
                : `Requête rejetée. Niveau ${consistency} non atteignable avec les pannes actuelles. (${details})`}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import { Database, BarChart2, MapPin, Zap, CircleDashed, Globe } from "lucide-react";
import * as d3 from "d3";

// ─── Constantes Murmur3 ────────────────────────────────────────────────────────
const MIN_TOKEN = -9223372036854775808n;
const MAX_TOKEN = 9223372036854775807n;
const TOTAL_RING = 18446744073709551616n; // 2^64

const formatToken = (tStr) => {
  if (!tStr) return "";
  return Number(tStr).toExponential(2);
};

// ─── Couleurs par DC ───────────────────────────────────────────────────────────
const DC_PALETTE = {
  dc1: { ring: "#4f46e5", label: "#818cf8", bg: "#4f46e510" },
  dc2: { ring: "#10b981", label: "#34d399", bg: "#10b98110" },
  dc3: { ring: "#f59e0b", label: "#fbbf24", bg: "#f59e0b10" },
  dc4: { ring: "#ef4444", label: "#f87171", bg: "#ef444410" },
};
const DC_DEFAULT = { ring: "#64748b", label: "#94a3b8", bg: "#64748b10" };

// ─── Composant : Accordéon par Nœud (Custom Shadcn-like Épuré) ────────────────
function NodeAccordion({ nodeInfo }) {
  const [isOpen, setIsOpen] = useState(false);
  const { node, globalIdx, ranges } = nodeInfo;
  const nodeColor = `var(--node-${globalIdx % 5})`;

  return (
    <div style={{ border: "1px solid var(--border-light)", borderRadius: "var(--radius-md)", overflow: "hidden", background: "var(--bg-app)", boxShadow: "var(--shadow-sm)" }}>
      {/* ── Header Accordéon ── */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        style={{ width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center", padding: "1rem 1.25rem", background: isOpen ? "var(--bg-surface)" : "var(--bg-app)", border: "none", cursor: "pointer", outline: "none", transition: "background 0.2s" }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "1rem" }}>
          <div style={{ width: 14, height: 14, borderRadius: "50%", background: nodeColor, boxShadow: `0 0 6px ${nodeColor}80` }}></div>
          <strong style={{ color: nodeColor, fontSize: 14, fontWeight: 700 }}>Nœud {globalIdx + 1}</strong>
          <span style={{ color: "var(--text-secondary)", fontSize: 13 }}>
            {node.address} <span style={{ opacity: 0.6 }}>(DC: {node.datacenter || "dc1"})</span>
          </span>
          <span className="badge badge-neutral" style={{ fontSize: 11 }}>{ranges.length} vnodes</span>
        </div>
        <div style={{ transform: isOpen ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.3s ease", color: "var(--text-tertiary)" }}>
          ▼
        </div>
      </button>

      {/* ── Contenu (Tableau Épuré) ── */}
      {isOpen && (
        <div style={{ padding: "0 1.25rem 1.25rem 1.25rem", borderTop: "1px solid var(--border-light)", background: "var(--bg-surface)", overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12, textAlign: "left", marginTop: "1rem" }}>
            <thead>
              <tr style={{ borderBottom: "2px solid var(--border-light)", color: "var(--text-secondary)" }}>
                <th style={{ padding: "0.75rem", width: "5%" }}>#</th>
                <th style={{ padding: "0.75rem", width: "65%", textAlign: "center" }}>Plage [Début → Fin]</th>
                <th style={{ padding: "0.75rem", width: "30%", textAlign: "right" }}>Portion (%)</th>
              </tr>
            </thead>
            <tbody>
              {ranges.length === 0 ? (
                <tr><td colSpan="3" style={{ textAlign: "center", padding: "1rem", color: "var(--text-tertiary)" }}>Aucun token assigné</td></tr>
              ) : ranges.map((r, idx) => (
                <tr key={idx} style={{ borderBottom: "1px solid var(--border-light)50" }}>
                  <td style={{ padding: "0.75rem", color: "var(--text-tertiary)", fontWeight: 600 }}>{idx + 1}</td>
                  
                  {/* Colonne Plage avec Grid pour un alignement symétrique parfait des flèches */}
                  <td style={{ padding: "0.75rem", fontFamily: "monospace", color: "var(--text-primary)", fontSize: 13 }}>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr auto 1fr", alignItems: "center", gap: "1.5rem" }}>
                      <span title={r.startStr} style={{ borderBottom: "1px dotted #9ca3af", cursor: "help", textAlign: "right", color: "var(--text-secondary)" }}>
                        {formatToken(r.startStr)}
                      </span>
                      <span style={{ color: "var(--primary-color)", fontWeight: 700, fontSize: 14 }}>→</span>
                      <span title={r.tokenStr} style={{ borderBottom: "1px dotted #9ca3af", cursor: "help", fontWeight: 700, textAlign: "left" }}>
                        {formatToken(r.tokenStr)}
                      </span>
                    </div>
                  </td>
                  
                  {/* Colonne Portion (Progress bar) */}
                  <td style={{ padding: "0.75rem", textAlign: "right" }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "flex-end", gap: "10px" }}>
                      <span style={{ fontWeight: 600 }}>{r.percent}%</span>
                      <div style={{ width: "60px", height: "6px", background: "var(--border-light)", borderRadius: 3, overflow: "hidden" }}>
                        <div style={{ height: "100%", width: `${r.percent}%`, background: nodeColor }}></div>
                      </div>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─── Sous-composant : un anneau SVG pour un DC ────────────────────────────────
function DcRing({ dcName, dcNodes, dcNodesWithTokens, globalIndices, highlightToken, downNodes }) {
  const svgRef = useRef();
  const palette = DC_PALETTE[dcName] || DC_DEFAULT;
  const SIZE = 380;
  const cx = SIZE / 2, cy = SIZE / 2, r = 130;

  useEffect(() => {
    if (!dcNodes.length) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const totalNodes = dcNodes.length;

    const logicalSegments = dcNodes.map((_, i) => ({
      nodeIdx: i,
      startAngle: (i / totalNodes) * 2 * Math.PI - Math.PI / 2,
      endAngle: ((i + 1) / totalNodes) * 2 * Math.PI - Math.PI / 2,
    }));

    const addrToNWT = new Map((dcNodesWithTokens || []).map(n => [n.address, n]));
    const orderedNWT = dcNodes.map(n => addrToNWT.get(n.address) || { tokens: [] });

    const getResponsibleIdx = (tokenStr) => {
      try {
        const allTokens = [];
        orderedNWT.forEach((node, localIdx) => {
          (node.tokens || []).forEach(tok => allTokens.push({ token: tok, localIdx }));
        });
        allTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
        if (!allTokens.length) return 0;
        const t = BigInt(tokenStr);
        for (let i = 0; i < allTokens.length; i++) {
          if (t <= BigInt(allTokens[i].token)) return allTokens[i].localIdx;
        }
        return allTokens[0].localIdx;
      } catch { return 0; }
    };

    let primaryNodeIdx = highlightToken ? getResponsibleIdx(highlightToken) : 0;
    primaryNodeIdx = Math.max(0, Math.min(primaryNodeIdx, dcNodes.length - 1));
    const getNodeColor = (localIdx) => `var(--node-${(globalIndices?.[localIdx] ?? localIdx) % 5})`;

    const downSegs = logicalSegments.filter(seg => {
      const nd = dcNodes[seg.nodeIdx];
      return downNodes.has(nd.address) || !nd.is_up;
    });
    if (downSegs.length > 0) {
      svg.append("rect")
        .attr("x", cx - 140).attr("y", 5).attr("width", 280).attr("height", 24).attr("rx", 7)
        .attr("fill", "var(--error-bg)").attr("stroke", "var(--error-color)").attr("stroke-width", 1);
      svg.append("text")
        .attr("x", cx).attr("y", 17).attr("text-anchor", "middle").attr("dominant-baseline", "central")
        .attr("fill", "var(--error-color)").attr("font-size", 10).attr("font-weight", "700").attr("font-family", "Inter")
        .text(`⚠ ${downSegs.length} nœud(s) en panne`);
    }

    svg.append("circle").attr("cx", cx).attr("cy", cy).attr("r", r)
      .attr("fill", "none").attr("stroke", "var(--border-light)").attr("stroke-width", 30).attr("opacity", 0.25);

    logicalSegments.forEach((seg) => {
      const x1 = cx + r * Math.cos(seg.startAngle);
      const y1 = cy + r * Math.sin(seg.startAngle);
      const x2 = cx + r * Math.cos(seg.endAngle);
      const y2 = cy + r * Math.sin(seg.endAngle);
      const largeArc = (seg.endAngle - seg.startAngle) > Math.PI ? 1 : 0;
      const nd = dcNodes[seg.nodeIdx];
      const isDown = downNodes.has(nd.address) || !nd.is_up;
      const isHighlight = highlightToken && primaryNodeIdx === seg.nodeIdx;
      const segColor = getNodeColor(seg.nodeIdx);

      svg.append("path")
        .attr("d", `M ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2}`)
        .attr("fill", "none")
        .attr("stroke", isDown ? "var(--text-tertiary)" : segColor)
        .attr("stroke-width", 30)
        .attr("opacity", isDown ? 0.2 : isHighlight ? 1 : 0.45)
        .style("transition", "opacity 0.3s ease");

      svg.append("line")
        .attr("x1", cx + (r - 16) * Math.cos(seg.startAngle)).attr("y1", cy + (r - 16) * Math.sin(seg.startAngle))
        .attr("x2", cx + (r + 16) * Math.cos(seg.startAngle)).attr("y2", cy + (r + 16) * Math.sin(seg.startAngle))
        .attr("stroke", "var(--bg-surface)").attr("stroke-width", 4).attr("stroke-linecap", "round");
    });

    dcNodes.forEach((node, i) => {
      const seg = logicalSegments[i];
      const midAngle = (seg.startAngle + seg.endAngle) / 2;
      const nodeR = r + 48;
      const x = cx + nodeR * Math.cos(midAngle);
      const y = cy + nodeR * Math.sin(midAngle);

      const isPrimary = highlightToken && primaryNodeIdx === i;
      const isSimDown = downNodes.has(node.address);
      const isRealDown = !node.is_up;
      const isDown = isSimDown || isRealDown;
      const nodeColor = getNodeColor(i);

      svg.append("line")
        .attr("x1", cx + r * Math.cos(midAngle)).attr("y1", cy + r * Math.sin(midAngle))
        .attr("x2", x).attr("y2", y)
        .attr("stroke", nodeColor).attr("stroke-width", 2).attr("opacity", 0.35).attr("stroke-dasharray", "3,3");

      if (isDown) {
        svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 22)
          .attr("fill", "var(--error-bg)").attr("stroke", "var(--error-color)").attr("stroke-width", 2).attr("opacity", 0.5);
      } else if (isPrimary) {
        const halo = svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 26)
          .attr("fill", "none").attr("stroke", nodeColor).attr("stroke-width", 2);
        halo.node().classList.add("animate-pulse-ring");
      }

      svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 20)
        .attr("fill", isDown ? "var(--text-tertiary)" : "var(--bg-surface)")
        .attr("stroke", isDown ? "var(--border-light)" : nodeColor)
        .attr("stroke-width", 3)
        .style("filter", "drop-shadow(0 4px 6px rgba(0,0,0,0.1))");

      svg.append("text").attr("x", x).attr("y", y + 1)
        .attr("text-anchor", "middle").attr("dominant-baseline", "central")
        .attr("fill", isDown ? "white" : nodeColor)
        .attr("font-size", 12).attr("font-weight", "700").attr("font-family", "Inter")
        .text(`N${(globalIndices?.[i] ?? i) + 1}`);

      if (isPrimary) {
        svg.append("rect").attr("x", x - 33).attr("y", y + 25).attr("width", 66).attr("height", 18).attr("rx", 9)
          .attr("fill", nodeColor).style("filter", "drop-shadow(0 2px 4px rgba(0,0,0,0.2))");
        svg.append("text").attr("x", x).attr("y", y + 35)
          .attr("text-anchor", "middle").attr("fill", "white").attr("font-size", 9).attr("font-weight", "700")
          .attr("letter-spacing", "0.5px").attr("font-family", "Inter").text("PRIMAIRE");
      }
    });

    if (highlightToken != null) {
      const seg = logicalSegments[primaryNodeIdx];
      const midAngle = (seg.startAngle + seg.endAngle) / 2;
      const dr = r - 42;
      const x = cx + dr * Math.cos(midAngle);
      const y = cy + dr * Math.sin(midAngle);
      const primaryColor = getNodeColor(primaryNodeIdx);

      svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 8)
        .attr("fill", "var(--bg-surface)").attr("stroke", primaryColor).attr("stroke-width", 3)
        .style("filter", `drop-shadow(0 0 6px ${primaryColor})`);
      svg.append("line")
        .attr("x1", cx + (r - 15) * Math.cos(midAngle)).attr("y1", cy + (r - 15) * Math.sin(midAngle))
        .attr("x2", x).attr("y2", y)
        .attr("stroke", primaryColor).attr("stroke-width", 2).attr("stroke-dasharray", "3,3").attr("opacity", 0.6);
      svg.append("text").attr("x", x).attr("y", y - 16)
        .attr("text-anchor", "middle").attr("fill", "var(--text-primary)").attr("font-size", 12).attr("font-weight", "700")
        .attr("font-family", "Inter").text("Donnée");
    }

    svg.append("circle").attr("cx", cx).attr("cy", cy).attr("r", 50)
      .attr("fill", "var(--bg-app)").attr("stroke", palette.ring).attr("stroke-width", 1).attr("opacity", 0.6);
    svg.append("text").attr("x", cx).attr("y", cx - 7)
      .attr("text-anchor", "middle").attr("dominant-baseline", "central")
      .attr("fill", palette.label).attr("font-size", 13).attr("font-weight", "700").attr("font-family", "Inter")
      .text(dcName.toUpperCase());
    svg.append("text").attr("x", cx).attr("y", cx + 10)
      .attr("text-anchor", "middle").attr("dominant-baseline", "central")
      .attr("fill", "var(--text-tertiary)").attr("font-size", 9).attr("font-family", "Inter")
      .text(`${dcNodes.length} nœuds`);

  }, [dcNodes, dcNodesWithTokens, highlightToken, downNodes, globalIndices, palette]);

  return (
    <div style={{
      display: "flex", flexDirection: "column", alignItems: "center", gap: "0.5rem",
      background: palette.bg, border: `1.5px solid ${palette.ring}40`,
      borderRadius: 16, padding: "1.25rem 1rem 1rem"
    }}>
      <div style={{ fontSize: 12, fontWeight: 700, color: palette.label, textTransform: "uppercase", letterSpacing: 1, display: "flex", alignItems: "center", gap: "0.3rem" }}>
        <Database size={14} /> {dcName.toUpperCase()}
      </div>
      <svg ref={svgRef} width={SIZE} height={SIZE} style={{ overflow: "visible" }} />
    </div>
  );
}

// ─── Composant principal ───────────────────────────────────────────────────────
export default function TokenRing({ nodes, nodesWithTokens, highlightToken, downNodes = new Set(), strategy = "simple" }) {

  // ✅ Logique avancée de calcul des plages (VNodes)
  const renderTokenTable = () => {
    if (!nodesWithTokens || nodesWithTokens.length === 0) return null;

    const allTokens = [];
    nodesWithTokens.forEach((node, nodeIdx) => {
      (node.tokens || []).forEach(t => {
        allTokens.push({ tokenVal: BigInt(t), tokenStr: t, address: node.address, dc: node.datacenter, nodeIdx });
      });
    });

    if (allTokens.length === 0) return null;

    allTokens.sort((a, b) => (a.tokenVal < b.tokenVal ? -1 : 1));

    const ranges = allTokens.map((item, i) => {
      const prevIdx = i === 0 ? allTokens.length - 1 : i - 1;
      const prevItem = allTokens[prevIdx];
      const start = prevItem.tokenVal;
      const end = item.tokenVal;

      let size;
      if (start < end) {
        size = end - start;
      } else {
        size = (MAX_TOKEN - start) + (end - MIN_TOKEN);
      }

      const percent = Number((size * 10000n) / TOTAL_RING) / 100;

      return {
        ...item,
        startStr: prevItem.tokenStr,
        percent: percent.toFixed(2)
      };
    });

    const nodesMap = new Map();
    nodesWithTokens.forEach((n, i) => {
      nodesMap.set(n.address, { node: n, globalIdx: i, ranges: [] });
    });
    ranges.forEach(r => {
      if (nodesMap.has(r.address)) {
        nodesMap.get(r.address).ranges.push(r);
      }
    });

    const nodeInfos = Array.from(nodesMap.values());

    return (
      <div style={{ marginTop: "3rem", width: "100%", maxWidth: 1000 }}>
        <h3 style={{ margin: "0 0 1.2rem", fontSize: 15, color: "var(--text-primary)", textTransform: "uppercase", letterSpacing: "0.5px", textAlign: "center", display: "flex", justifyContent: "center", alignItems: "center", gap: "0.5rem" }}>
          <BarChart2 size={18} /> Plages de Hachage Détaillées (VNodes)
        </h3>
        
        <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
          {nodeInfos.map(info => (
            <NodeAccordion key={info.node.address} nodeInfo={info} />
          ))}
        </div>

        <p style={{ marginTop: "1.5rem", fontSize: 13, color: "var(--text-tertiary)", lineHeight: 1.5, textAlign: "center" }}>
          <em>* Astuce : Survolez un token pour afficher sa valeur Murmur3 complète.<br/>
          La « Portion » représente le pourcentage exact de l'anneau de hachage global couvert par cette plage.</em>
        </p>
      </div>
    );
  };

  // ── Mode NTS : un anneau par DC ─────────────────────────────────────────────
  if (strategy === "nts") {
    const dcs = [...new Set(nodes.map(n => n.datacenter))].sort();

    return (
      <div style={{ width: "100%", display: "flex", flexDirection: "column", alignItems: "center", gap: "2rem" }}>
        <div style={{ display: "flex", gap: "2rem", flexWrap: "wrap", justifyContent: "center" }}>
          {dcs.map(dc => {
            const dcNodeEntries = nodes
              .map((n, globalIdx) => ({ n, globalIdx }))
              .filter(({ n }) => n.datacenter === dc);
            const dcNodes = dcNodeEntries.map(({ n }) => n);
            const globalIndices = dcNodeEntries.map(({ globalIdx }) => globalIdx);
            const dcAddresses = new Set(dcNodes.map(n => n.address));
            const dcNodesWithTokens = nodesWithTokens.filter(n => dcAddresses.has(n.address));
            return (
              <DcRing
                key={dc}
                dcName={dc}
                dcNodes={dcNodes}
                dcNodesWithTokens={dcNodesWithTokens}
                globalIndices={globalIndices}
                highlightToken={highlightToken}
                downNodes={downNodes}
              />
            );
          })}
        </div>

        <div style={{ maxWidth: 500, margin: "0 auto", background: "var(--bg-app)", padding: "1.2rem", borderRadius: "var(--radius-md)", border: "1px solid var(--border-light)" }}>
          <h4 style={{ margin: "0 0 0.8rem", color: "var(--text-primary)", fontSize: 13, textTransform: "uppercase", letterSpacing: "0.5px" }}>
            <><Globe size={14} style={{marginRight:4}}/> NetworkTopologyStrategy</> — Multi-DC
          </h4>
          <ul style={{ margin: 0, padding: 0, listStyle: "none", display: "flex", flexDirection: "column", gap: "0.7rem", fontSize: 13, color: "var(--text-secondary)", lineHeight: 1.5 }}>
            <li style={{ display: "flex", gap: "0.5rem", alignItems: "flex-start" }}>
              <Database size={16} style={{ color: "var(--primary-color)", marginTop: 2, flexShrink: 0 }} />
              <span>Chaque data center possède <strong>son propre anneau de hachage</strong>, indépendant des autres DC.</span>
            </li>
            <li style={{ display: "flex", gap: "0.5rem", alignItems: "flex-start" }}>
              <MapPin size={16} style={{ color: "var(--primary-color)", marginTop: 2, flexShrink: 0 }} />
              <span>Le point indique où la donnée atterrit <strong>dans chaque DC</strong>. Le nœud marqué <em>PRIMAIRE</em> en est responsable localement.</span>
            </li>
            <li style={{ display: "flex", gap: "0.5rem", alignItems: "flex-start" }}>
              <Zap size={16} style={{ color: "var(--primary-color)", marginTop: 2, flexShrink: 0 }} />
              <span>La réplication inter-DC se fait via le réseau WAN — chaque DC reçoit sa propre copie.</span>
            </li>
          </ul>
        </div>
        
        {renderTokenTable()}
      </div>
    );
  }

  // ── Mode SimpleStrategy : anneau unique (comportement originel) ──────────────
  return (
    <div style={{ width: "100%", display: "flex", flexDirection: "column", alignItems: "center", gap: "2rem" }}>
      <SingleRing nodes={nodes} nodesWithTokens={nodesWithTokens} highlightToken={highlightToken} downNodes={downNodes} />
      {renderTokenTable()}
    </div>
  );
}

// ─── Anneau simple (SimpleStrategy) ──────────────────────────────────────────
function SingleRing({ nodes, nodesWithTokens, highlightToken, downNodes }) {
  const svgRef = useRef();

  useEffect(() => {
    if (!nodes.length) return;
    const width = 400, height = 400, cx = 200, cy = 200, r = 130;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const totalNodes = nodes.length;
    const logicalSegments = nodes.map((_, i) => ({
      nodeIdx: i,
      startAngle: (i / totalNodes) * 2 * Math.PI - Math.PI / 2,
      endAngle: ((i + 1) / totalNodes) * 2 * Math.PI - Math.PI / 2,
    }));

    const getResponsibleNodeIdx = (tokenStr) => {
      if (!nodesWithTokens || nodesWithTokens.length === 0) return 0;
      const allTokens = [];
      nodesWithTokens.forEach((node, nodeIdx) => {
        (node.tokens || []).forEach(tok => allTokens.push({ token: tok, nodeIdx }));
      });
      allTokens.sort((a, b) => (BigInt(a.token) < BigInt(b.token) ? -1 : 1));
      if (allTokens.length === 0) return 0;
      const t = BigInt(tokenStr);
      for (let i = 0; i < allTokens.length; i++) {
        if (t <= BigInt(allTokens[i].token)) return allTokens[i].nodeIdx;
      }
      return allTokens[0].nodeIdx;
    };

    let primaryNodeIdx = 0;
    if (highlightToken) primaryNodeIdx = getResponsibleNodeIdx(highlightToken);

    const getNodeColor = (idx) => `var(--node-${idx % 5})`;

    svg.append("circle").attr("cx", cx).attr("cy", cy).attr("r", r)
      .attr("fill", "none").attr("stroke", "var(--border-light)").attr("stroke-width", 30).attr("opacity", 0.3);

    const downSegments = logicalSegments.filter(seg => {
      const segNode = nodes[seg.nodeIdx];
      return downNodes.has(segNode.address) || !segNode.is_up;
    });

    if (downSegments.length > 0) {
      svg.append("rect").attr("x", cx - 140).attr("y", 5).attr("width", 280).attr("height", 28).attr("rx", 8)
        .attr("fill", "var(--error-bg)").attr("stroke", "var(--error-color)").attr("stroke-width", 1);
      svg.append("text").attr("x", cx).attr("y", 19).attr("text-anchor", "middle").attr("dominant-baseline", "central")
        .attr("fill", "var(--error-color)").attr("font-size", 11).attr("font-weight", "700").attr("font-family", "Inter")
        .text(`⚠ ${downSegments.length} nœud(s) en panne sur cet anneau`);
    }

    logicalSegments.forEach((seg) => {
      const x1 = cx + r * Math.cos(seg.startAngle);
      const y1 = cy + r * Math.sin(seg.startAngle);
      const x2 = cx + r * Math.cos(seg.endAngle);
      const y2 = cy + r * Math.sin(seg.endAngle);
      const largeArc = (seg.endAngle - seg.startAngle) > Math.PI ? 1 : 0;
      const isHighlightSegment = highlightToken !== null && primaryNodeIdx === seg.nodeIdx;
      const segNode = nodes[seg.nodeIdx];
      const isSegDown = downNodes.has(segNode.address) || !segNode.is_up;

      svg.append("path")
        .attr("d", `M ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2}`)
        .attr("fill", "none")
        .attr("stroke", isSegDown ? "var(--text-tertiary)" : getNodeColor(seg.nodeIdx))
        .attr("stroke-width", 30)
        .attr("opacity", isSegDown ? 0.3 : isHighlightSegment ? 1 : 0.4)
        .style("transition", "opacity 0.3s ease");

      svg.append("line")
        .attr("x1", cx + (r - 16) * Math.cos(seg.startAngle)).attr("y1", cy + (r - 16) * Math.sin(seg.startAngle))
        .attr("x2", cx + (r + 16) * Math.cos(seg.startAngle)).attr("y2", cy + (r + 16) * Math.sin(seg.startAngle))
        .attr("stroke", "var(--bg-surface)").attr("stroke-width", 4).attr("stroke-linecap", "round");
    });

    nodes.forEach((node, i) => {
      const seg = logicalSegments[i];
      const midAngle = (seg.startAngle + seg.endAngle) / 2;
      const nodeR = r + 45;
      const x = cx + nodeR * Math.cos(midAngle);
      const y = cy + nodeR * Math.sin(midAngle);
      const isPrimary = highlightToken && primaryNodeIdx === i;
      const nodeColor = getNodeColor(i);
      const isSimDown = downNodes.has(node.address);
      const isReallyDown = !node.is_up;
      const isDown = isSimDown || isReallyDown;

      svg.append("line")
        .attr("x1", cx + r * Math.cos(midAngle)).attr("y1", cy + r * Math.sin(midAngle))
        .attr("x2", x).attr("y2", y)
        .attr("stroke", nodeColor).attr("stroke-width", 2).attr("opacity", 0.4).attr("stroke-dasharray", "3,3");

      if (isDown) {
        svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 22)
          .attr("fill", "var(--error-bg)").attr("stroke", "var(--error-color)").attr("stroke-width", 2).attr("opacity", 0.5);
      } else if (isPrimary) {
        const halo = svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 26)
          .attr("fill", "none").attr("stroke", nodeColor).attr("stroke-width", 2);
        halo.node().classList.add("animate-pulse-ring");
      }

      svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 20)
        .attr("fill", !isDown ? "var(--bg-surface)" : "var(--text-tertiary)")
        .attr("stroke", !isDown ? nodeColor : "var(--border-light)").attr("stroke-width", 3)
        .style("filter", "drop-shadow(0 4px 6px rgba(0,0,0,0.1))");

      svg.append("text").attr("x", x).attr("y", y + 1)
        .attr("text-anchor", "middle").attr("dominant-baseline", "central")
        .attr("fill", !isDown ? nodeColor : "white")
        .attr("font-size", 13).attr("font-weight", "700").attr("font-family", "Inter")
        .text(`N${i + 1}`);

      if (isPrimary) {
        svg.append("rect").attr("x", x - 35).attr("y", y + 26).attr("width", 70).attr("height", 20).attr("rx", 10)
          .attr("fill", nodeColor).style("filter", "drop-shadow(0 2px 4px rgba(0,0,0,0.2))");
        svg.append("text").attr("x", x).attr("y", y + 37)
          .attr("text-anchor", "middle").attr("fill", "white").attr("font-size", 10).attr("font-weight", "700")
          .attr("letter-spacing", "0.5px").attr("font-family", "Inter").text("PRIMAIRE");
      }
    });

    if (highlightToken !== null && highlightToken !== undefined) {
      const seg = logicalSegments[primaryNodeIdx];
      const midAngle = (seg.startAngle + seg.endAngle) / 2;
      const dr = r - 40;
      const x = cx + dr * Math.cos(midAngle);
      const y = cy + dr * Math.sin(midAngle);

      svg.append("circle").attr("cx", x).attr("cy", y).attr("r", 8)
        .attr("fill", "var(--bg-surface)").attr("stroke", getNodeColor(primaryNodeIdx)).attr("stroke-width", 3)
        .style("filter", `drop-shadow(0 0 6px ${getNodeColor(primaryNodeIdx)})`);
      svg.append("line")
        .attr("x1", cx + (r - 15) * Math.cos(midAngle)).attr("y1", cy + (r - 15) * Math.sin(midAngle)).attr("x2", x).attr("y2", y)
        .attr("stroke", getNodeColor(primaryNodeIdx)).attr("stroke-width", 2).attr("stroke-dasharray", "3,3").attr("opacity", 0.6);
      svg.append("text").attr("x", x).attr("y", y - 16)
        .attr("text-anchor", "middle").attr("fill", "var(--text-primary)").attr("font-size", 13).attr("font-weight", "700")
        .attr("font-family", "Inter").text("Donnée");
    }

    svg.append("circle").attr("cx", cx).attr("cy", cy).attr("r", 55)
      .attr("fill", "var(--bg-app)").attr("stroke", "var(--border-light)").attr("stroke-width", 1);
    svg.append("text").attr("x", cx).attr("y", cy)
      .attr("text-anchor", "middle").attr("dominant-baseline", "central")
      .attr("fill", "var(--text-tertiary)").attr("font-size", 11).attr("font-weight", "600")
      .attr("font-family", "Inter").attr("letter-spacing", "1px").text("CLUSTER");

  }, [nodes, nodesWithTokens, highlightToken, downNodes]);

  return (
    <div style={{ display: "flex", gap: "2rem", flexWrap: "wrap", alignItems: "center", justifyContent: "center", width: "100%" }}>
      <div style={{ position: "relative" }}>
        <svg ref={svgRef} width={400} height={400} style={{ overflow: "visible" }} />
      </div>
      <div style={{ maxWidth: 300, background: "var(--bg-app)", padding: "1.2rem", borderRadius: "var(--radius-md)", border: "1px solid var(--border-light)" }}>
        <h4 style={{ margin: "0 0 0.8rem", color: "var(--text-primary)", fontSize: 13, textTransform: "uppercase", letterSpacing: "0.5px" }}>L'anneau de hachage</h4>
        <ul style={{ margin: 0, padding: 0, listStyle: "none", display: "flex", flexDirection: "column", gap: "0.8rem", fontSize: 13, color: "var(--text-secondary)", lineHeight: 1.5 }}>
          <li style={{ display: "flex", gap: "0.5rem", alignItems: "flex-start" }}>
            <CircleDashed size={16} style={{ color: "var(--primary-color)", marginTop: 2, flexShrink: 0 }} />
            <span>Pour plus de clarté, l'anneau est divisé en <strong>{nodes.length} parts égales</strong> (une par nœud physique).</span>
          </li>
          <li style={{ display: "flex", gap: "0.5rem", alignItems: "flex-start" }}>
            <MapPin size={16} style={{ color: "var(--primary-color)", marginTop: 2, flexShrink: 0 }} />
            <span>Le point indique l'emplacement de ta donnée. Elle tombe naturellement dans la portion gérée par son <strong>Nœud Primaire</strong>.</span>
          </li>
        </ul>
      </div>
    </div>
  );
}

